package main

import (
	"container/heap"
	"math"
)

type State struct {
	cost int64
	t    int64
	i    int64
	j    int64
}

type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*State)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	if m == 0 {
		return 0
	}
	n := len(grid[0])
	if n == 0 {
		return 0
	}

	// Precompute teleport_map
	teleport_map := make([][][]int, m)
	for i := 0; i < m; i++ {
		teleport_map[i] = make([][]int, n)
		for j := 0; j < n; j++ {
			teleport_map[i][j] = make([][2]int, 0)
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if grid[x][y] <= grid[i][j] {
						teleport_map[i][j] = append(teleport_map[i][j], [2]int{x, y})
					}
				}
			}
		}
	}

	// Initialize distance array
	dist := make([][][]int64, m)
	for i := 0; i < m; i++ {
		dist[i] = make([][]int64, n)
		for j := 0; j < n; j++ {
			dist[i][j] = make([]int64, k+1)
			for t := 0; t <= int(k); t++ {
				dist[i][j][t] = math.MaxInt64
			}
		}
	}

	// Initialize priority queue
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &State{0, 0, 0, 0})

	for pq.Len() > 0 {
		state := heap.Pop(&pq).(*State)
		cost := state.cost
		t := state.t
		i := state.i
		j := state.j

		// Check if we reached the destination
		if i == int64(m-1) && j == int64(n-1) {
			return cost
		}

		// Check if current cost is higher than the recorded distance
		if cost > dist[int(i)][int(j)][int(t)] {
			continue
		}

		// Regular moves: right and down
		dirs := [][2]int{{0, 1}, {1, 0}}
		for _, dir := range dirs {
			ni := i + int64(dir[0])
			nj := j + int64(dir[1])
			if ni < int64(m) && nj < int64(n) {
				new_cost := cost + grid[int(ni)][int(nj)]
				if new_cost < dist[int(ni)][int(nj)][int(t)] {
					dist[int(ni)][int(nj)][int(t)] = new_cost
					heap.Push(&pq, &State{new_cost, t, ni, nj})
				}
			}
		}

		// Teleportation
		if t < k {
			for _, coord := range teleport_map[int(i)][int(j)] {
				x, y := coord[0], coord[1]
				new_t := t + 1
				if cost < dist[x][y][new_t] {
					dist[x][y][new_t] = cost
					heap.Push(&pq, &State{cost, new_t, int64(x), int64(y)})
				}
			}
		}
	}

	// If not found (should not happen)
	return -1
}
